package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.visitor.VoidVisitorAdapter;
import java.io.File;
import java.util.List;

public class Main {
    public static void main(String[] args) throws Exception {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source-file-or-directory>");
            System.exit(1);
        }

        File input = new File(args[0]);
        if (input.isDirectory()) {
            processDirectory(input);
        } else {
            processFile(input);
        }
    }

    private static void processDirectory(File dir) throws Exception {
        for (File file : dir.listFiles((d, name) -> name.endsWith(".java"))) {
            processFile(file);
        }
    }

    private static void processFile(File file) throws Exception {
        try {
            CompilationUnit cu = StaticJavaParser.parse(file);

            DnsApiFixVisitor visitor = new DnsApiFixVisitor();
            visitor.visit(cu, null);

            if (visitor.hasChanges()) {
                StaticJavaParser.printer().print(cu, file);
                System.out.println("Fixed: " + file.getPath());
            }
        } catch (Exception e) {
            System.err.println("Error processing " + file.getPath() + ": " + e.getMessage());
        }
    }

    static class DnsApiFixVisitor extends VoidVisitorAdapter<Void> {
        private boolean hasChanges = false;

        public boolean hasChanges() {
            return hasChanges;
        }

        @Override
        public void visit(MethodCallExpr methodCall, Void arg) {
            super.visit(methodCall, arg);

            String methodName = methodCall.getNameAsString();

            if ("create".equals(methodName)) {
                List<com.github.javaparser.ast.expr.Expression> args = methodCall.getArguments();

                if (args.size() == 2) {
                    String secondArgType = getExpressionType(args.get(1));
                    if ("ManagedZone".equals(secondArgType) || "zone".equals(args.get(1).toString().toLowerCase())) {
                        methodCall.setArgument(1, null);
                        MethodCallExpr setContentCall = new MethodCallExpr(methodCall, "setContent");
                        setContentCall.addArgument(args.get(1));
                        methodCall.replace(setContentCall);
                        hasChanges = true;
                    }
                } else if (args.size() == 3) {
                    String thirdArgType = getExpressionType(args.get(2));
                    if ("Change".equals(thirdArgType) || "changeRequest".equals(args.get(2).toString().toLowerCase())) {
                        methodCall.removeArgument(2);
                        MethodCallExpr setContentCall = new MethodCallExpr(methodCall, "setContent");
                        setContentCall.addArgument(args.get(2));
                        methodCall.replace(setContentCall);
                        hasChanges = true;
                    }
                }
            }
        }

        private String getExpressionType(com.github.javaparser.ast.expr.Expression expr) {
            String str = expr.toString();
            if (str.contains("ManagedZone")) return "ManagedZone";
            if (str.contains("Change")) return "Change";
            return null;
        }
    }
}

